import 'dotenv/config';
import { AcmeClient } from '@acme/sdk';

const client = new AcmeClient({
  apiKey: process.env.ACME_API_KEY,
  environment: process.env.ACME_ENVIRONMENT,
});

interface Resource {
  id: string;
  name: string;
  type: string;
  status: 'active' | 'archived';
  metadata: Record<string, unknown>;
  tags: string[];
  createdAt: string;
  updatedAt: string;
}

interface User {
  id: string;
  email: string;
  name: string;
  role: 'admin' | 'member' | 'viewer';
  lastLoginAt: string | null;
  createdAt: string;
}

interface AcmeConfig {
  apiKey: string;
  environment?: 'development' | 'staging' | 'production';
  baseUrl?: string;
  timeout?: number;
  maxRetries?: number;
  cache?: CacheConfig | false;
}

interface ApiResponse<T> {
  data: T;
  meta: {
    requestId: string;
    timestamp: string;
  };
}

interface PaginatedResponse<T> {
  data: T[];
  nextCursor: string | null;
  totalCount: number;
  meta: {
    requestId: string;
    timestamp: string;
  };
}

class AcmeError extends Error {
  code: string;
  statusCode: number;
}

class ValidationError extends AcmeError {
  errors: { field: string; message: string }[];
}

class RateLimitError extends AcmeError {
  retryAfter: number;
}
